@@private
<%_
const stat = (typeof getvar === 'function' ? getvar('stat_data') : ((typeof variables !== 'undefined' && variables.stat_data) ? variables.stat_data : {})) || {};
const period = _.get(stat, 'world_time.period', '沦陷期');
const allowedMap = {
  '沦陷期': ['普通感染者', '奔跑种', '食腐种', '夜视种'],
  '末日期初期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种'],
  '末日期中期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种', '毒气种', '母巢', '融合型'],
  '末日期末期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种', '毒气种', '母巢', '融合型'],
  '巢化期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种', '毒气种', '母巢', '融合型', '残巢种', '变异体'],
  '重建期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种', '毒气种', '母巢', '融合型', '残巢种', '变异体']
};
const allTypes = allowedMap['重建期'];
const allowed = allowedMap[period] || allowedMap['沦陷期'];
const forbidden = allTypes.filter(x => !allowed.includes(x));
const compact = {
  user_profile: _.pick(_.get(stat, 'user_profile', {}), ['origin_identity', 'opening_location', 'current_location', 'current_goal', 'skills']),
  world_time: _.get(stat, 'world_time', {}),
  survival: _.get(stat, 'survival', {}),
  inventory: _.get(stat, 'inventory', {}),
  mainline: _.get(stat, 'mainline', {}),
  factions: _.get(stat, 'factions', {}),
  npcs: _.pickBy(_.get(stat, 'npcs', {}), v => v && v.status !== '未遇见'),
  quests: _.get(stat, 'quests', {}),
  local_events: _.get(stat, 'local_events', {}),
  monster_knowledge: _.get(stat, 'monster_knowledge', {})
};
_%>
<status_current_variables>
当前时期: <%- period %>
当前可正式出现怪物: <%- allowed.join('、') %>
禁止提前正式登场怪物: <%- forbidden.length ? forbidden.join('、') : '无' %>
规则: 禁止让未到时期的怪物实际遭遇或造成战斗；只能作为传闻、误判、记录或梦境。
当前变量快照:
<%- JSON.stringify(compact, null, 2) %>
</status_current_variables>

@@preprocessing
<%_
if (typeof blMainStage === 'undefined') var blMainStage = getvar('stat_data.mainline.stage', { defaults: '未接触' }) || '未接触';
var blMainMap = {
  "未接触": "主线-远方归来",
  "远方归来": "主线-远方归来",
  "水源疑点": "主线-水源里的旧事故",
  "拓展J": "主线-拓展 J 的名字",
  "军方封锁": "主线-封锁不是救援",
  "食蚁兽模型": "主线-食蚁兽没有停止",
  "黑光III": "主线-黑光-III",
  "真相之后": "主线-真相之后"
};
var blMainEntry = blMainMap[blMainStage] || blMainMap['未接触'];
_%>
<%- await getwi(blMainEntry) %>

@@preprocessing
<%_
if (typeof blQuestLoc === 'undefined') var blQuestLoc = getvar('stat_data.user_profile.current_location', { defaults: '' }) || '';
if (typeof blQuestActive === 'undefined') var blQuestActive = getvar('stat_data.quests.active', { defaults: [] }) || [];
if (typeof blQuestCompleted === 'undefined') var blQuestCompleted = getvar('stat_data.quests.completed', { defaults: [] }) || [];
if (typeof blQuestFailed === 'undefined') var blQuestFailed = getvar('stat_data.quests.failed', { defaults: [] }) || [];
var blSideMap = {
  "安娜·陈": "支线-观察期",
  "索菲亚·金": "支线-缺口",
  "阿德勒": "支线-封锁线以北",
  "韦斯特": "支线-失败样本",
  "徐银": "支线-不能被写进损耗栏的人",
  "牧师": "支线-上帝是否动摇",
  "石井雄介": "支线-焦虑",
  "莎拉": "支线-抉择",
  "卡尔·J·雷耶斯": "支线-账本里的死路",
  "卢卡斯·卡雷": "支线-不该进去的地方"
};
var blQuestCandidates = [];
function blPushQuest(npcName) {
  var entryName = blSideMap[npcName];
  if (entryName && !blQuestCandidates.includes(entryName)) blQuestCandidates.push(entryName);
}
for (var i = 0; i < blQuestActive.length; i++) {
  var q = blQuestActive[i];
  var qText = typeof q === 'string' ? q : JSON.stringify(q);
  Object.keys(blSideMap).forEach(function(npcName) { if (qText.includes(npcName) || qText.includes(blSideMap[npcName].replace('支线-', ''))) blPushQuest(npcName); });
}
if (blQuestLoc.includes('新都')) { blPushQuest('安娜·陈'); blPushQuest('索菲亚·金'); }
if (blQuestLoc.includes('封锁线') || blQuestLoc.includes('哨站') || blQuestLoc.includes('防疫军')) blPushQuest('阿德勒');
if (blQuestLoc.includes('韦斯特') || blQuestLoc.includes('研究所')) blPushQuest('韦斯特');
if (blQuestLoc.includes('学联') || blQuestLoc.includes('避难点')) { blPushQuest('徐银'); blPushQuest('牧师'); }
if (blQuestLoc.includes('沿江') || blQuestLoc.includes('医院')) { blPushQuest('石井雄介'); blPushQuest('莎拉'); }
if (blQuestLoc.includes('兄弟会') || blQuestLoc.includes('莱伊')) { blPushQuest('卡尔·J·雷耶斯'); blPushQuest('卢卡斯·卡雷'); }
var blQuestShown = 0;
_%>
<%_ for (var i = 0; i < blQuestCandidates.length && blQuestShown < 2; i++) { var qName = blQuestCandidates[i]; if (!blQuestCompleted.includes(qName.replace('支线-', '')) && !blQuestCompleted.includes(qName) && !blQuestFailed.includes(qName.replace('支线-', '')) && !blQuestFailed.includes(qName)) { blQuestShown++; _%>
<%- await getwi(qName) %>
<%_ }} _%>

@@preprocessing
<%_
