if (blLoc.includes('努尔') || blLoc.includes('山脉') || blLoc.includes('巡护') || blLoc.includes('瞭望')) blRegion = '努尔山脉';
else if (blLoc.includes('新都')) blRegion = '新都';
else if (blLoc.includes('韦斯特') || blLoc.includes('研究所') || blLoc.includes('11区郊外')) blRegion = '11区郊外';
